import parse from 'html-react-parser';
import moment from 'moment';
import React from 'react';
import ContentLoader from 'react-content-loader';
import { NavLink, useLocation, useNavigate } from 'react-router-dom';
import Footer from '../../Component/Footer/Footer';
import Navbar from '../../Component/Navbar';
const SinglePostPage = (prop) => {
  const history = useLocation()
  const navigate = useNavigate()
  const { pathname } = useLocation();
  console.log(history);
  React.useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  // const Loader = () => (
  // <ContentLoader style={{width:'100%', height:"400"}}  >
  //   <path d="M484.52,64.61H15.65C7.1,64.61.17,71.2.17,79.31V299.82c0,8.12,6.93,14.7,15.48,14.7H484.52c8.55,0,15.48-6.58,15.48-14.7V79.31C500,71.2,493.07,64.61,484.52,64.61Zm-9,204.34c0,11.84-7.14,21.44-15.94,21.44H436.39L359.16,171.52c-7.1-10.92-19.67-11.16-27-.51L258.64,277.94C253.78,285,245.73,286,240,280.2l-79.75-80.62c-6-6.06-14.33-5.7-20,.88L62.34,290.39H40.63c-8.8,0-15.94-9.6-15.94-21.44V110.19c0-11.84,7.14-21.44,15.94-21.44H459.54c8.8,0,15.94,9.6,15.94,21.44Z" />
  // </ContentLoader>
  // )

  const Spinner = () => (
    <div style={{ display: 'flex', height: 400, justifyContent: 'center', alignItems: 'center' }}>
      <svg className="spinner" viewBox="0 0 50 50">
        <circle className="path" cx="25" cy="25" r="20" fill="none" strokeWidth="5"></circle>
      </svg>
    </div >
  )
  return (<>
    <Navbar />
    <div className="singlepage">

      <div className="singlepage-image">
      </div>
      <div className="singlepage-box shadow">
        <div className="singlepage-content">

          <i className='fa fa-arrow-alt-circle-left' onClick={() => navigate(-1)} />

          <div className='date'>{moment().format('LL')}</div>
          <h1>{history.state.title}</h1>
          <div className="break-line">
            <svg >
              <path d="M 10 10 L 300 10" />
            </svg>
          </div>
          <div className="image">

            {/* <Loader /> */}
            {history.state.image_lg ? <img src={history.state.image_lg} loading="lazy" alt={history.state.title} /> : <Spinner />}
          </div>
          <div className="description">{parse(history.state.description)}</div>
          <div className='social-share'>
            <p>Share on</p>
            <ul>
              <li><a href="#"><i className='fab fa-facebook' /></a></li>
              <li><a href="#"><i className='fab fa-instagram' /></a></li>
              <li><a href="#"><i className='fab fa-youtube' /></a></li>
              <li><a href="#"><i className='fab fa-whatsapp' /></a></li>
              <li><a href="#"><i className='fas fa-envelope' /></a></li>
            </ul>
          </div>
          <div className="related-post">

          </div>
        </div>
      </div>
    </div>
    <Footer />
  </>

  );
};

export default SinglePostPage;
